Actionscript.script:
stop();
var speed = 3;
var moveReady = true;
var currentLevel = 1;
var currentCheck = check1;
var currentCoins = 0;
var coins = new Array();
coins.push(0);
coins.push(1);
coins.push(1);
coins.push(3);
coins.push(0);
coins.push(4);
coins.push(4);
coins.push(3);
coins.push(1);
coins.push(0);
coins.push(2);
coins.push(1);
coins.push(0);
coins.push(0);
coins.push(0);
coins.push(4);
coins.push(0);
coins.push(67);
coins.push(0);
coins.push(7);
coins.push(3);
coins.push(0);
coins.push(36);
coins.push(0);
coins.push(0);
coins.push(4);
coins.push(1);
coins.push(0);
coins.push(2);
coins.push(4);
var deaths = 0;
bars.levelText = currentLevel + "/30";
bars.deathsText = "DEATHS: " + deaths;

onClipEvent(load){
   _root.currentCheck = _root.check1;
   _X = _root.currentCheck._x;
   _Y = _root.currentCheck._y;
}
onClipEvent(enterFrame){
   if(hitTest(_root.check2) && _root.currentCheck == _root.check1)
   {
      _root.currentCheck = _root.check2;
   }
   if(hitTest(_root.check3) && _root.currentCoins == _root.coins[_root.currentLevel - 1])
   {
      _root.currentLevel++;
      _root.bars.levelText = _root.currentLevel + "/30";
      _root.currentCoins = 0;
      _root.nextFrame();
   }
   if(!_root.moveReady)
   {
      if(_alpha > 0)
      {
         _alpha = _alpha - 4;
      }
      else
      {
         _root.deaths++;
         _root.bars.deathsText = "DEATHS: " + _root.deaths;
         _alpha = 100;
         _X = _root.currentCheck._x;
         _Y = _root.currentCheck._y;
         _root.moveReady = true;
      }
   }
   if((Key.isDown(39) || Key.isDown(68)) && _root.moveReady)
   {
      _X = _X + _root.speed;
   }
   if((Key.isDown(37) || Key.isDown(65)) && _root.moveReady)
   {
      _X = _X - _root.speed;
   }
   if((Key.isDown(38) || Key.isDown(87)) && _root.moveReady)
   {
      _Y = _Y - _root.speed;
   }
   if((Key.isDown(40) || Key.isDown(83)) && _root.moveReady)
   {
      _Y = _Y + _root.speed;
   }
   if(_root.walls.hitTest(_X + _width / 2 - _root.speed,_Y,true))
   {
      _X = _X - _root.speed;
   }
   if(_root.walls.hitTest(_X - _width / 2 + _root.speed,_Y,true))
   {
      _X = _X + _root.speed;
   }
   if(_root.walls.hitTest(_X,_Y - _height / 2 + _root.speed,true))
   {
      _Y = _Y + _root.speed;
   }
   if(_root.walls.hitTest(_X,_Y + _height / 2 - _root.speed,true))
   {
      _Y = _Y - _root.speed;
   }
   if(_root.enemies.hitTest(_X,_Y,true) && _alpha == 100)
   {
      _root.moveReady = false;
      this.gotoAndPlay(3);
   }
   else if(_root.enemies.hitTest(_X + _width / 2,_Y,true) && _alpha == 100)
   {
      _root.moveReady = false;
      this.gotoAndPlay(3);
   }
   else if(_root.enemies.hitTest(_X - _width / 2,_Y,true) && _alpha == 100)
   {
      _root.moveReady = false;
      this.gotoAndPlay(3);
   }
   else if(_root.enemies.hitTest(_X,_Y - _height / 2,true) && _alpha == 100)
   {
      _root.moveReady = false;
      this.gotoAndPlay(3);
   }
   else if(_root.enemies.hitTest(_X,_Y + _height / 2,true) && _alpha == 100)
   {
      _root.moveReady = false;
      this.gotoAndPlay(3);
   }
}

